import socket
import requests

def scan_iot_devices(network_prefix):
    """Scan network for IoT devices and check basic vulnerabilities"""
    vulnerabilities = []

    for i in range(1, 255):
        ip = f"{network_prefix}.{i}"

        # Check for open ports common in IoT devices
        common_ports = [80, 443, 8080, 8443]

        for port in common_ports:
            if check_port_open(ip, port):
                device_info = check_device_security(ip, port)
                if device_info:
                    vulnerabilities.append(device_info)

    return vulnerabilities

def check_port_open(ip, port):
    """Check if a port is open"""
    sock = socket.socket(socket.AF_INET, socket.SOCK_STREAM)
    sock.settimeout(1)
    result = sock.connect_ex((ip, port))
    sock.close()
    return result == 0

def check_device_security(ip, port):
    """Check for basic security issues"""
    try:
        # Check for default login pages
        if port in [80, 8080]:
            # Simple check - in reality would analyze response
            return {"ip": ip, "port": port, "issue": "Web interface exposed"}
    except:
        pass
    return None

